sql:
SELECT fruit_id
FROM fruits
WHERE maturity_level = 'ripe' AND mass > 150;

SELECT AVG(redness) AS average_redness
FROM fruits
WHERE class = 'apple';

SELECT class, mass
FROM fruits
WHERE redness > 3.0 AND yellowness < 2.0;

SELECT COUNT(fruit_id) AS total_fruits, AVG(mass) AS average_mass
FROM fruits
WHERE source_id = 1 AND collection_date LIKE '2023%';

SELECT AVG(redness) AS average_redness
FROM fruits
WHERE class = 'apple' AND harvest_date BETWEEN '2023-01-01' AND '2023-12-31';

SELECT batch_name
FROM batches
WHERE quality_score > 85;

SELECT AVG(mass) AS average_apple_mass
FROM fruits
WHERE class = 'apple' AND harvest_date > '2023-08-01';

SELECT class, COUNT(*) AS fruit_count
FROM fruits
GROUP BY class;

SELECT class
FROM fruits
WHERE fruit_id = 1;

SELECT f.class, AVG(f.mass) AS average_mass_per_class
FROM fruits f
GROUP BY f.class;

external_knowledge:
- Intense weather conditions refer to the weather data with values greater than 50;
- The terms "typical levels" imply the average values of redness and yellowness;
- The fruits are associated with weather data through their unique identifiers.

- "known source" refers to "Farm A".;
- "specific cool and moist conditions" refers to "10°C, 85% humidity".;
- "typical color characteristics" is represented by the average redness and yellowness values.;

sql:
SELECT batch_name, AVG(quality_score) AS average_quality_score
FROM batches
GROUP BY batch_name;

SELECT AVG(mass) AS average_mass
FROM fruits
WHERE class = 'apple' AND maturity_level = 'ripe';

SELECT average_mass AS typical_mass
FROM batches
WHERE batch_name = 'Batch 1';

SELECT average_mass, average_volume
FROM batches
WHERE batch_id = 1;

SELECT COUNT(fruit_id) AS total_fruits_harvested
FROM fruits
WHERE harvested_by = (SELECT user_id FROM users WHERE user_name = 'Alice Johnson');
